import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

cpp_sources = """
#include <torch/torch.h>

void matmul_with_bias_relu(torch::Tensor A, torch::Tensor B, torch::Tensor bias, torch::Tensor out) {
    const int M = A.size(0);
    const int K = A.size(1);

    for (int i = 0; i < M; ++i) {
        float sum = 0.0f;
        for (int j = 0; j < K; ++j) {
            sum += A[i * K + j] * B[j];
        }
        out[i] = std::max(sum + bias[0], 0.0f);
    }
}
"""

cuda_sources = """
#include <torch/torch.h>
#include <cuda_runtime.h>
#include <algorithm> // Include for std::max

__global__ void matmul_with_bias_relu_kernel(const float* A, const float* B, const float* bias, float* out, int M, int K) {
    int row = blockIdx.y * blockDim.y + threadIdx.y;
    int col = blockIdx.x * blockDim.x + threadIdx.x;

    if (row < M && col == 0) {
        float sum = 0.0f;
        for (int k = 0; k < K; ++k) {
            sum += A[row * K + k] * B[k];
        }
        out[row] = std::max(sum + bias[0], 0.0f);
    }
}

void matmul_with_bias_relu_cuda(torch::Tensor A, torch::Tensor B, torch::Tensor bias, torch::Tensor out) {
    const int M = A.size(0);
    const int K = A.size(1);

    dim3 grid((M + 255) / 256, 1, 1);
    dim3 block(256, 1, 1);

    matmul_with_bias_relu_kernel<<<grid, block>>>(A.data_ptr<float>(), B.data_ptr<float>(), bias.data_ptr<float>(), out.data_ptr<float>(), M, K);
    cudaDeviceSynchronize();
}
"""

