#include <torch/extension.h>
#include <cuda_runtime.h>

#define TILE_SIZE 16

__global__ void matmul_relu_kernel(float* A, float* B, float* C, int M, int K, int N) {
    __shared__ float s_A[TILE_SIZE][TILE_SIZE];
    __shared__ float s_B[TILE_SIZE][TILE_SIZE];

    int row = blockIdx.y * TILE_SIZE + threadIdx.y;
    int col = blockIdx.x * TILE_SIZE + threadIdx.x;

    float c_value = 0.0f;

    for (int k = 0; k < K; k += TILE_SIZE) {
        if (row < M && k + threadIdx.y < K) {
            s_A[threadIdx.y][threadIdx.x] = A[row * K + k + threadIdx.y];
        } else {
            s_A[threadIdx.y][threadIdx.x] = 0.0f;
        }

        if (col < N && k + threadIdx.x < K) {
            s_B[threadIdx.y][threadIdx.x] = B[(k + threadIdx.x) * N + col];
        } else {
            s_B[threadIdx.y][threadIdx.x] = 0.0f;
        }

        __syncthreads();

        for (int m = 0; m < TILE_SIZE; ++m) {
            c_value += s_A[m][threadIdx.x] * s_B[threadIdx.y][m];
        }

        __syncthreads();
    }

    if (row < M && col < N) {
        C[row * N + col] = max(c_value, 0.0f);
    }
}

torch::Tensor matmul_relu(torch::Tensor A, torch::Tensor B) {
    int M = A.size(0);
    int K = A.size(1);
    int N = B.size(1);

    auto options = torch::TensorOptions().dtype(torch::kFloat32).device(torch::kCUDA);
    torch::Tensor C = torch::empty({M, N}, options);

    dim3 blocks((N + TILE_SIZE - 1) / TILE_SIZE, (M + TILE_SIZE - 1) / TILE_SIZE, 1);
    dim3 threads(TILE_SIZE, TILE_SIZE, 1);

    matmul_relu_kernel<<<blocks, threads>>>(A.data_ptr<float>(), B.data_ptr<float>(), C.data_ptr<float>(), M, K, N);

    return C;
}
