#include <torch/extension.h>
#include <cuda_runtime.h>

#define TILE_SIZE 16

__global__ void gemm_with_bias_relu(const float* A, const float* B, const float* bias, float* C, int M, int K, int N) {
    __shared__ float As[TILE_SIZE][TILE_SIZE];
    __shared__ float Bs[TILE_SIZE][TILE_SIZE];

    int row = blockIdx.y * blockDim.y + threadIdx.y;
    int col = blockIdx.x * blockDim.x + threadIdx.x;

    float c = 0.0f;

    for (int k = 0; k < K; k += TILE_SIZE) {
        if (row < M && k + threadIdx.x < K) {
            As[threadIdx.y][threadIdx.x] = A[row * K + k + threadIdx.x];
        } else {
            As[threadIdx.y][threadIdx.x] = 0.0f;
        }

        if (col < N && k + threadIdx.y < K) {
            Bs[threadIdx.x][threadIdx.y] = B[(k + threadIdx.y) * N + col];
        } else {
            Bs[threadIdx.x][threadIdx.y] = 0.0f;
        }

        __syncthreads();

        for (int m = 0; m < TILE_SIZE; ++m) {
            c += As[threadIdx.y][m] * Bs[m][threadIdx.x];
        }

        __syncthreads();
    }

    if (row < M && col < N) {
        c += bias[col];
        c = max(c, 0.0f);
        C[row * N + col] = c;
    }
}

