    dim3 threads(TILE_SIZE, TILE_SIZE, 1);

    gemm_with_bias_relu<<<blocks, threads>>>(A.data_ptr<float>(), B.data_ptr<float>(), bias.data_ptr<float>(), C.data_ptr<float>(), M, K, N);

