__global__ void mish_fused_kernel(
    const torch::PackedTensorAccessor<scalar_t, 4> input,
    torch::PackedTensorAccessor<scalar_t, 4> output,
    int N, int C, int H, int W) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= N * C * H * W) return;

    int n = idx / (C * H * W);
    int c = (idx / (H * W)) % C;
    int h = (idx / W) % H;
    int w = idx % W;

    scalar_t val = input[n][c][h][w];
    scalar_t e_val = exp(val);
    scalar_t mish_val = val * (e_val + 1) / (e_val - 1);

    output[n][c][h][w] = mish_val;
