#include <torch/torch.h>
#include <cuda_runtime.h>

__global__ void relu_batch_norm_dropout_kernel(const float* input, const float* weight, const float* bias, const float* running_mean, const float* running_var, float eps, float* output, float dropout_prob, int N, int C, int H, int W) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= N * C * H * W) return;

    int n = idx / (C * H * W);
    int c = (idx / (H * W)) % C;
    int h = (idx / W) % H;
    int w = idx % W;

    float inv_std = 1.0f / sqrt(running_var[c] + eps);
    float val = input[idx];
    float normalized_val = (val - running_mean[c]) * inv_std;
    output[idx] = weight[c] * normalized_val + bias[c];

    float rand_val = static_cast<float>(rand()) / RAND_MAX;
    if (rand_val > dropout_prob) {
        output[idx] *= 1.0f / (1.0f - dropout_prob);
    } else {
        output[idx] = 0.0f;
    }
}

void relu_batch_norm_dropout_cuda(torch::Tensor input, torch::Tensor weight, torch::Tensor bias, torch::Tensor running_mean, torch::Tensor running_var, float eps, torch::Tensor output, float dropout_prob) {
